// Google Ads API not configured — graceful skip
return [{ json: {
  status: 'skipped',
  reason: 'Google Ads not configured — set TG_GOOGLE_ADS_CUSTOMER_ID to enable conversion monitoring',
  timestamp: new Date().toISOString()
} }];

// Calculate 48-hour window
const now = new Date();
const fortyEightHoursAgo = new Date(now.getTime() - 48 * 60 * 60 * 1000);
const twoDaysAgoStr = fortyEightHoursAgo.toISOString().split('T')[0];
const today = now.toISOString().split('T')[0];

return [{ json: { today, twoDaysAgoStr, nowIso: now.toISOString() } }];

// Group by campaign, sum conversions and cost over 48h
// Flag campaigns where conversions=0 AND cost>0
const response = $input.first().json;
const rows = response.body || response || [];

if (!Array.isArray(rows) || rows.length === 0) {
  return [{ json: { zeroConversionCampaigns: [], count: 0, status: 'no_data' } }];
}

// Group by campaign
const campaigns = {};
for (const row of rows) {
  const id = row.campaign_id || 'unknown';
  if (!campaigns[id]) {
    campaigns[id] = {
      campaign_id: id,
      campaign_name: row.campaign_name || id,
      total_cost: 0,
      total_conversions: 0,
      days: 0
    };
  }
  campaigns[id].total_cost += parseFloat(row.cost) || 0;
  campaigns[id].total_conversions += parseFloat(row.conversions) || 0;
  campaigns[id].days += 1;
}

// Flag zero-conversion campaigns that are spending money
const zeroConversionCampaigns = Object.values(campaigns)
  .filter(c => c.total_conversions === 0 && c.total_cost > 0)
  .map(c => ({
    ...c,
    total_cost: Math.round(c.total_cost * 100) / 100
  }))
  .sort((a, b) => b.total_cost - a.total_cost);

return [{ json: {
  zeroConversionCampaigns,
  count: zeroConversionCampaigns.length,
  totalWastedSpend: Math.round(zeroConversionCampaigns.reduce((s, c) => s + c.total_cost, 0) * 100) / 100,
  status: zeroConversionCampaigns.length > 0 ? 'zero_conversions_found' : 'all_converting'
} }];

// All campaigns converting — no issues
return [{ json: {
  status: 'all_converting',
  message: 'All active campaigns have conversions in the last 48 hours',
  timestamp: new Date().toISOString()
} }];
